class Solution:
    def minimumCost(self, cost1, cost2, costBoth, need1, need2):
        best = None
        upper = need1 + need2
        for k in range(0, upper + 1):
            remaining1 = max(0, need1 - k)
            remaining2 = max(0, need2 - k)
            total = k * costBoth + remaining1 * cost1 + remaining2 * cost2
            if best is None or total < best:
                best = total
        return best

