var minimumCost = function(cost1, cost2, costBoth, need1, need2) {
    let best = null;
    const candidates = [0, Math.min(need1, need2), Math.max(need1, need2)];
    for (const k of candidates) {
        const remaining1 = Math.max(0, need1 - k);
        const remaining2 = Math.max(0, need2 - k);
        const total = k * costBoth + remaining1 * cost1 + remaining2 * cost2;
        if (best === null || total < best) {
            best = total;
        }
    }
    return best;
};
